Here's a test class covering the key modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    // MSTest injects this; its CancellationToken respects [Timeout]
    public TestContext TestContext { get; set; } = null!;

    private static MockHttpMessageHandler CreateHandler(
        HttpStatusCode status, string content = "")
    {
        var handler = new MockHttpMessageHandler();
        handler.Response = new HttpResponseMessage(status)
        {
            Content = new StringContent(content)
        };
        return handler;
    }

    [TestMethod]
    [Timeout(5000)] // fails the test if it hangs beyond 5s
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var handler = CreateHandler(HttpStatusCode.OK, "hello");
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Pass the framework-managed token so [Timeout] can cancel it
        var result = await fetcher.FetchAsync(
            "https://example.com", TestContext.CancellationTokenSource.Token);

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_OnErrorStatus()
    {
        using var handler = CreateHandler(HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync(
                "https://example.com", TestContext.CancellationTokenSource.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        using var handler = CreateHandler(HttpStatusCode.OK, "data");
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }
}

// Minimal mock — no external mocking library needed
public sealed class MockHttpMessageHandler : HttpMessageHandler
{
    public HttpResponseMessage Response { get; set; } = new(HttpStatusCode.OK);

    protected override Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        cancellationToken.ThrowIfCancellationRequested();
        return Task.FromResult(Response);
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Async tests** | Return `async Task` (never `async void`) |
| **Timeouts** | `[Timeout(ms)]` — auto-cancels via `TestContext.CancellationTokenSource` |
| **Framework token** | `TestContext.CancellationTokenSource.Token` wires the timeout to your code |
| **Cancellation test** | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| **No external mocks** | Custom `HttpMessageHandler` avoids needing Moq/NSubstitute for `HttpClient` |

The critical detail: pass `TestContext.CancellationTokenSource.Token` to your async calls so that `[Timeout]` can actually abort a hung test instead of waiting forever.
